ALGORITHM SR_Latch
INPUT: S (Set), R (Reset), current_Q
OUTPUT: next_Q, next_Q_bar

BEGIN
 // SR Latch with NOR gates - level sensitive
 // S=1, R=0 -> Set state (Q=1)
 // S=0, R=1 -> Reset state (Q=0)
 // S=0, R=0 -> Hold previous state
 // S=1, R=1 -> Invalid/Forbidden state

 IF S == 1 AND R == 1 THEN
 // Forbidden state: both outputs become 0
 // This violates Q and Q' complementary relationship
 next_Q = 0
 next_Q_bar = 0
 PRINT "WARNING: Invalid state - both S and R are HIGH"
 ELSE IF S == 1 AND R == 0 THEN
 // Set: Force Q to 1
 next_Q = 1
 next_Q_bar = 0
 ELSE IF S == 0 AND R == 1 THEN
 // Reset: Force Q to 0
 next_Q = 0
 next_Q_bar = 1
 ELSE
 // S=0, R=0: Hold state - retain previous value
 next_Q = current_Q
 next_Q_bar = NOT current_Q
 END IF

 RETURN next_Q, next_Q_bar
END ALGORITHM

ALGORITHM Gated_SR_Latch
INPUT: S, R, E (Enable), current_Q
OUTPUT: next_Q

BEGIN
 // Gated SR Latch - only responds when Enable=1
 IF E == 1 THEN
 // When enabled, behave like SR latch
 next_Q = SR_Latch(S, R, current_Q)
 ELSE
 // When disabled, hold the current state
 next_Q = current_Q
 END IF
 RETURN next_Q
END ALGORITHM

ALGORITHM D_Latch
INPUT: D (Data), E (Enable), current_Q
OUTPUT: next_Q

BEGIN
 // D Latch - eliminates invalid state problem
 // When E=1: Output follows input (transparent)
 // When E=0: Hold previous state

 IF E == 1 THEN
 // Transparent mode: Q follows D
 next_Q = D
 ELSE
 // Latched mode: maintain previous value
 next_Q = current_Q
 END IF
 RETURN next_Q
END ALGORITHM

/*
 * LATCH CIRCUIT SIMULATION
 * ========================
 * Educational simulation of digital latches:
 * - SR Latch (NOR-based, active-high)
 * - Gated SR Latch (with Enable input)
 * - D Latch (Data Latch)
 * 
 * Demonstrates level-sensitive behavior of latches
 */

#include <stdio.h>
#include <stdbool.h>

/* SR Latch Structure using NOR gates */
typedef struct {
 bool Q; // Output
 bool Q_bar; // Complementary output
} SRLatch;

/* Initialize SR Latch */
void sr_latch_init(SRLatch *latch) {
 latch->Q = 0;
 latch->Q_bar = 1; // Initial valid state
}

/* SR Latch update function - follows truth table */
void sr_latch_update(SRLatch *latch, bool S, bool R) {
 /*
 * Truth Table:
 * S=0, R=0: Hold (memory) - Q(t+1) = Q(t)
 * S=0, R=1: Reset - Q(t+1) = 0
 * S=1, R=0: Set - Q(t+1) = 1
 * S=1, R=1: Invalid (forbidden) - both outputs = 0
 */

 if (S == 1 && R == 1) {
 printf(" WARNING: Invalid state! S=R=1 violates Q=~Q'\n");
 latch->Q = 0;
 latch->Q_bar = 0;
 } else if (S == 1 && R == 0) {
 latch->Q = 1;
 latch->Q_bar = 0;
 } else if (S == 0 && R == 1) {
 latch->Q = 0;
 latch->Q_bar = 1;
 } else {
 /* S=0, R=0: Hold - maintain current state */
 latch->Q_bar = !latch->Q;
 }
}

/* Gated SR Latch */
typedef struct {
 bool Q;
 bool Q_bar;
 bool internal_S; /* Output of AND gate for S and E */
 bool internal_R; /* Output of AND gate for R and E */
} GatedSRLatch;

void gated_sr_init(GatedSRLatch *latch) {
 latch->Q = 0;
 latch->Q_bar = 1;
 latch->internal_S = 0;
 latch->internal_R = 0;
}

void gated_sr_update(GatedSRLatch *latch, bool S, bool R, bool E) {
 /*
 * Gated SR Latch operation:
 * - When E=0: AND gates output 0,0 -> SR latch in hold state
 * - When E=1: S and R pass through to internal SR latch
 */

 /* AND gates - enable control */
 latch->internal_S = S && E;
 latch->internal_R = R && E;

 printf(" Internal signals: S'=%d, R'=%d (E=%d)\n", 
 latch->internal_S, latch->internal_R, E);

 /* Update internal SR latch */
 if (latch->internal_S == 1 && latch->internal_R == 1) {
 printf(" WARNING: Invalid internal state!\n");
 latch->Q = 0;
 latch->Q_bar = 0;
 } else if (latch->internal_S == 1 && latch->internal_R == 0) {
 latch->Q = 1;
 latch->Q_bar = 0;
 } else if (latch->internal_S == 0 && latch->internal_R == 1) {
 latch->Q = 0;
 latch->Q_bar = 1;
 } else {
 /* Hold state */
 latch->Q_bar = !latch->Q;
 }
}

/* D Latch - Most practical type */
typedef struct {
 bool Q;
 /* Note: D latch can be implemented as gated SR with inverter */
 /* D connects to S, ~D connects to R */
} DLatch;

void d_latch_init(DLatch *latch) {
 latch->Q = 0;
}

void d_latch_update(DLatch *latch, bool D, bool E) {
 /*
 * D Latch operation:
 * - E=1 (Enable HIGH): Transparent mode - Q follows D
 * - E=0 (Enable LOW): Latched mode - holds last value
 * 
 * This is equivalent to Gated SR where:
 * - S = D AND E
 * - R = ~D AND E
 * Since D and ~D are always opposite, invalid state is IMPOSSIBLE
 */

 if (E == 1) {
 /* Transparent: Q follows D directly */
 latch->Q = D;
 printf(" Mode: TRANSPARENT (E=1) - Q follows D\n");
 } else {
 /* Latched: Hold current state - inputs ignored */
 printf(" Mode: LATCHED (E=0) - holding Q=%d\n", latch->Q);
 }
}

/* Print functions */
void print_sr_state(SRLatch *latch) {
 printf("Q=%d, Q'=%d\n", latch->Q, latch->Q_bar);
}

void print_gated_sr_state(GatedSRLatch *latch) {
 printf("Q=%d, Q'=%d\n", latch->Q, latch->Q_bar);
}

void print_d_state(DLatch *latch) {
 printf("Q=%d\n", latch->Q);
}

/* Main demonstration */
int main() {
 printf("========================================\n");
 printf(" LATCH CIRCUIT SIMULATION IN C\n");
 printf("========================================\n\n");

 /* Test 1: SR Latch */
 printf("=== 1. SR LATCH (NOR-based) ===\n");
 SRLatch sr;
 sr_latch_init(&sr);

 printf("Test S=0, R=0 (Hold): ");
 sr_latch_update(&sr, 0, 0);
 print_sr_state(&sr);

 printf("Test S=1, R=0 (Set): ");
 sr_latch_update(&sr, 1, 0);
 print_sr_state(&sr);

 printf("Test S=0, R=0 (Hold): ");
 sr_latch_update(&sr, 0, 0);
 print_sr_state(&sr);

 printf("Test S=0, R=1 (Reset): ");
 sr_latch_update(&sr, 0, 1);
 print_sr_state(&sr);

 printf("Test S=1, R=1 (Invalid): ");
 sr_latch_update(&sr, 1, 1);
 print_sr_state(&sr);

 /* Test 2: Gated SR Latch */
 printf("\n=== 2. GATED SR LATCH ===\n");
 GatedSRLatch gated_sr;
 gated_sr_init(&gated_sr);

 printf("E=0, S=1, R=0 (Disabled - should hold):\n");
 gated_sr_update(&gated_sr, 1, 0, 0);
 print_gated_sr_state(&gated_sr);

 printf("E=1, S=1, R=0 (Enabled - Set):\n");
 gated_sr_update(&gated_sr, 1, 0, 1);
 print_gated_sr_state(&gated_sr);

 printf("E=0, S=1, R=0 (Disabled - hold previous):\n");
 gated_sr_update(&gated_sr, 1, 0, 0);
 print_gated_sr_state(&gated_sr);

 /* Test 3: D Latch */
 printf("\n=== 3. D LATCH (Data Latch) ===\n");
 printf("The D latch eliminates the invalid state problem!\n\n");

 DLatch d_latch;
 d_latch_init(&d_latch);

 printf("E=1, D=1 (Transparent):\n");
 d_latch_update(&d_latch, 1, 1);
 print_d_state(&d_latch);

 printf("E=1, D=0 (Transparent):\n");
 d_latch_update(&d_latch, 0, 1);
 print_d_state(&d_latch);

 printf("E=0 (Disabled - hold last value):\n");
 d_latch_update(&d_latch, 1, 0); /* D=1 ignored, E=0
 print_d_state(&d_latch);

 printf("E=0, still D=1 ignored:\n");
 d_latch_update(&d_latch, 1, 0);
 print_d_state(&d_latch);

 printf("E=1 (Enable again, capture D):\n");
 d_latch_update(&d_latch, 1, 1);
 print_d_state(&d_latch);

 /* Summary */
 printf("\n========================================\n");
 printf(" SUMMARY: LATCH vs FLIP-FLOP\n");
 printf("========================================\n");
 printf("LATCH: Level-sensitive\n");
 printf(" - Responds to entire duration of Enable=1\n");
 printf(" - Output can change multiple times while E=1\n");
 printf("\nFLIP-FLOP: Edge-triggered\n");
 printf(" - Samples input ONLY at clock transition\n");
 printf(" - Output changes only once per clock edge\n");

 return 0;
}
